import { useState, useEffect } from 'react';
import { LoadingDots } from './LoadingDots';

interface Answer {
  answer: string;
  confidence: number;
  cited_chunks: string[];
  retrieved_chunks: Array<{ chunk_id: string; score: number; text: string; source: string }>;
}

export function RagContextSection({ caseId }: { caseId: string }) {
  const [question, setQuestion] = useState('');
  const [loading, setLoading] = useState(false);
  const [answer, setAnswer] = useState<Answer | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [hasIndex, setHasIndex] = useState<boolean | null>(null);

  useEffect(() => {
    fetch('/api/v1/acp/invoke', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ capability: 'get_knowledge_graph', params: { case_id: caseId } }),
    }).then(r => r.json()).then(data => {
      setHasIndex(data.success && data.result?.n_nodes > 0);
    }).catch(() => setHasIndex(false));
  }, [caseId]);

  const handleAsk = async () => {
    if (!question.trim()) return;
    setLoading(true);
    setError(null);
    try {
      const resp = await fetch('/api/v1/acp/invoke', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ capability: 'query_rag', params: { question, case_id: caseId } }),
      });
      const data = await resp.json();
      if (data.success) setAnswer(data.result);
      else setError(data.error?.message || '查询失败');
    } catch {
      setError('网络错误');
    }
    setLoading(false);
  };

  return (
    <details className="report-section">
      <summary>📚 RAG 问答</summary>
      <div className="report-content" style={{ padding: '12px' }}>
        {hasIndex === false && (
          <p style={{ fontSize: '14px', color: '#64748b' }}>
            尚未入库 PDF。请到 RAG 页面入库后再提问。
          </p>
        )}
        <div style={{ display: 'flex', gap: '8px', marginBottom: '12px' }}>
          <input
            type="text" placeholder="针对本 case 的论文提问..." value={question}
            onChange={(e) => setQuestion(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleAsk()}
            style={{ flex: 1, padding: '8px 12px', border: '1px solid #e2e8f0', borderRadius: '8px' }}
            disabled={hasIndex === false}
          />
          <button className="btn-primary" onClick={handleAsk} disabled={loading || !question.trim()}>
            {loading ? <LoadingDots text="查询中" /> : '提问'}
          </button>
        </div>
        {answer && (
          <div style={{ padding: '12px', background: '#f8fafc', borderRadius: '8px' }}>
            <p>{answer.answer}</p>
            <div style={{ fontSize: '12px', color: '#64748b' }}>
              置信度: {(answer.confidence * 100).toFixed(0)}% · 引用: {answer.cited_chunks?.join(', ')}
            </div>
            {answer.retrieved_chunks && answer.retrieved_chunks.length > 0 && (
              <div style={{ marginTop: '8px' }}>
                {answer.retrieved_chunks.map((c, i) => (
                  <details key={i} style={{ marginBottom: '4px' }}>
                    <summary style={{ cursor: 'pointer', fontSize: '12px' }}>{c.chunk_id} (score={c.score})</summary>
                    <pre style={{ padding: '4px', background: '#fff', fontSize: '11px', whiteSpace: 'pre-wrap' }}>{c.text}</pre>
                  </details>
                ))}
              </div>
            )}
          </div>
        )}
        {error && <p style={{ color: '#ef4444', fontSize: '14px' }}>{error}</p>}
      </div>
    </details>
  );
}

import { createHashRouter } from 'react-router-dom';
import { Home } from './pages/Home';
import { Workbench } from './pages/Workbench';
import { RagPlaceholder } from './pages/RagPlaceholder';
import { Layout } from './components/Layout';

export const router = createHashRouter([
  {
    path: '/',
    element: <Layout><Home /></Layout>,
  },
  {
    path: '/workbench',
    element: <Layout><Workbench /></Layout>,
  },
  {
    path: '/workbench/:caseId',
    element: <Layout><Workbench /></Layout>,
  },
  {
    path: '/rag',
    element: <Layout><RagPlaceholder /></Layout>,
  },
]);

import { Link, useLocation } from 'react-router-dom';

export function Layout({ children }: { children: React.ReactNode }) {
  const location = useLocation();
  const isActive = (path: string) =>
    location.pathname === path || location.pathname.startsWith(path + '/');

  return (
    <div>
      <nav className="navbar" aria-label="主导航">
        <Link to="/" className="navbar-brand">PaperAgent</Link>
        <div className="navbar-links">
          <Link to="/" className={isActive('/') && location.pathname === '/' ? 'active' : ''}>首页</Link>
          <Link to="/workbench" className={isActive('/workbench') ? 'active' : ''}>工作台</Link>
          <Link to="/rag" className={isActive('/rag') ? 'active' : 'disabled'}>RAG</Link>
        </div>
      </nav>
      <div className="container">{children}</div>
    </div>
  );
}

export function LoadingDots({ text = '正在分析' }: { text?: string }) {
  return (
    <span className="loading-dots">
      <span>{text}</span>
      <span className="dots">
        <span className="dot"></span>
        <span className="dot"></span>
        <span className="dot"></span>
      </span>
    </span>
  );
}

interface ErrorStateProps {
  title: string;
  message: string;
  suggestion?: string;
  onRetry?: () => void;
}

const ERROR_SUGGESTIONS: Record<string, string> = {
  '400': '请检查输入的题目是否为空或包含非法字符',
  '404': '该研究记录不存在，可能已被清理',
  '429': 'API 调用频率过高，请稍后重试',
  '500': '服务器内部错误，请查看后端日志',
  'timeout': '请求超时，可能是 LLM 或外部 API 响应慢，请重试',
  'network': '网络连接失败，请确认后端服务是否在运行',
};

export function getErrorSuggestion(errorText: string): string {
  for (const [code, suggestion] of Object.entries(ERROR_SUGGESTIONS)) {
    if (errorText.includes(code)) return suggestion;
  }
  return '请稍后重试，或检查后端服务是否正常运行';
}

export function ErrorState({ title, message, suggestion, onRetry }: ErrorStateProps) {
  const autoSuggestion = suggestion || getErrorSuggestion(message);
  return (
    <div className="error-state">
      <div className="error-icon">⚠️</div>
      <div className="error-title">{title}</div>
      <div className="error-message">{message}</div>
      <div className="error-suggestion">💡 {autoSuggestion}</div>
      {onRetry && (
        <button className="btn-secondary" onClick={onRetry}>重试</button>
      )}
    </div>
  );
}

interface EmptyStateProps {
  icon?: string;
  title: string;
  description?: string;
  action?: { label: string; onClick: () => void };
}

export function EmptyState({ icon = '📭', title, description, action }: EmptyStateProps) {
  return (
    <div className="empty-state">
      <div className="empty-icon">{icon}</div>
      <div className="empty-title">{title}</div>
      {description && <div className="empty-desc">{description}</div>}
      {action && (
        <button className="btn-primary" onClick={action.onClick}>
          {action.label}
        </button>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { submitTopic, listCases } from '../lib/api';
import { EmptyState } from '../components/EmptyState';
import { LoadingDots } from '../components/LoadingDots';

const DEMO_CASES = [
  {
    title: '基于YOLO的钢材表面缺陷检测',
    description: '工业视觉质检场景，有公开数据集和 baseline',
    label: '工科 · 计算机视觉',
  },
  {
    title: '基于大语言模型的医学问答可信度评估方法研究',
    description: '医学AI合规场景，涉及安全性和可信度',
    label: '医学 · AI安全',
  },
];

interface CaseItem {
  case_id: string;
  status: string;
  mtime: number;
  topic?: string;
  score?: number;
}

interface ProviderInfo {
  name: string;
  model: string;
  label: string;
  enabled: boolean;
}

export function Home() {
  const navigate = useNavigate();
  const [topic, setTopic] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<CaseItem[]>([]);
  const [providers, setProviders] = useState<ProviderInfo[]>([]);
  const [activeProvider, setActiveProvider] = useState('');
  const [switching, setSwitching] = useState(false);

  useEffect(() => {
    listCases()
      .then(async (data) => {
        const cases = (data.cases || []).slice(0, 10);
        const enriched = await Promise.all(
          cases.map(async (c: CaseItem) => {
            try {
              const resp = await fetch(`/api/v1/research/${c.case_id}/state`);
              if (resp.ok) {
                const state = await resp.json();
                return {
                  ...c,
                  topic: state.topic as string,
                  score: state.feasibility_report?.score as number | undefined,
                };
              }
            } catch { /* ignore */ }
            return c;
          })
        );
        setHistory(enriched);
      })
      .catch(() => {});

    // Load providers
    fetch('/api/v1/llm/providers')
      .then(r => r.json())
      .then(data => {
        setProviders(data.providers || []);
        setActiveProvider(data.active_primary || '');
      })
      .catch(() => {});
  }, []);

  const handleSubmit = async (topicText?: string) => {
    const t = (topicText || topic).trim();
    if (!t) return;
    setLoading(true);
    setError(null);
    try {
      const result = await submitTopic(t);
      navigate(`/workbench/${result.case_id}`);
    } catch (e) {
      setError(e instanceof Error ? e.message : '提交失败');
      setLoading(false);
    }
  };

  const loadHistory = (caseId: string) => {
    navigate(`/workbench/${caseId}`);
  };

  const switchProvider = async (name: string) => {
    if (name === activeProvider) return;
    setSwitching(true);
    try {
      const resp = await fetch('/api/v1/llm/active', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'X-ACP-Capability': 'write' },
        body: JSON.stringify({ primary: name }),
      });
      const data = await resp.json();
      if (data.success) {
        setActiveProvider(name);
      }
    } catch { /* ignore */ }
    setSwitching(false);
  };

  return (
    <div>
      <div className="home-hero">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px' }}>
          <div>
            <h1>PaperAgent</h1>
            <div className="subtitle">题目研究智能工作台</div>
          </div>
          {providers.length > 0 && (
            <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px' }}>
              <span style={{ color: 'var(--color-text-secondary)' }}>🤖</span>
              <select
                value={activeProvider}
                onChange={(e) => switchProvider(e.target.value)}
                disabled={switching}
                style={{
                  padding: '4px 8px', borderRadius: '6px', border: '1px solid #e2e8f0',
                  background: '#fff', fontSize: '13px', cursor: 'pointer',
                }}
              >
                {providers.map(p => (
                  <option key={p.name} value={p.name}>
                    {p.label} ({p.model})
                  </option>
                ))}
              </select>
              {switching && <LoadingDots text="" />}
            </div>
          )}
        </div>

        <div className="description">
          输入一个题目，获得完整的证据链和可行性分析报告
        </div>

        <div className="home-steps">
          <div className="home-step">
            <div className="step-number">1️⃣</div>
            <div className="step-title">输入题目</div>
            <div className="step-desc">AI 自动分解关键词</div>
          </div>
          <div className="home-step">
            <div className="step-number">2️⃣</div>
            <div className="step-title">智能检索</div>
            <div className="step-desc">多源验证论文质量</div>
          </div>
          <div className="home-step">
            <div className="step-number">3️⃣</div>
            <div className="step-title">审核报告</div>
            <div className="step-desc">导出可行性报告</div>
          </div>
        </div>

        <div className="home-input-row">
          <input
            type="text"
            placeholder="🔍 输入题目..."
            value={topic}
            onChange={(e) => setTopic(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSubmit()}
            disabled={loading}
            aria-label="研究题目输入"
          />
          <button
            className="btn-primary"
            onClick={() => handleSubmit()}
            disabled={loading || !topic.trim()}
          >
            {loading ? <LoadingDots text="提交中" /> : '开始研究'}
          </button>
        </div>

        {error && (
          <div style={{ color: 'var(--color-error)', fontSize: '14px', marginBottom: '16px' }}>
            {error}
          </div>
        )}

        <div className="home-demos">
          {DEMO_CASES.map((demo) => (
            <div
              key={demo.title}
              className="demo-card"
              onClick={() => handleSubmit(demo.title)}
            >
              <div className="demo-label">{demo.label}</div>
              <div className="demo-title">{demo.title}</div>
              <div className="demo-desc">{demo.description}</div>
            </div>
          ))}
        </div>
      </div>

      <div className="home-history">
        <h3>最近研究</h3>
        {history.length === 0 ? (
          <EmptyState
            icon="📂"
            title="还没有研究记录"
            description="输入题目开始第一次研究"
          />
        ) : (
          <div className="history-list">
            {history.map((item) => (
              <div
                key={item.case_id}
                className="history-item"
                onClick={() => loadHistory(item.case_id)}
              >
                <div>
                  <span className="case-id">{item.case_id}</span>
                  {item.topic && (
                    <div style={{ fontSize: '13px', color: 'var(--color-text)', marginTop: '2px' }}>
                      {item.topic.length > 50 ? item.topic.slice(0, 50) + '...' : item.topic}
                    </div>
                  )}
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  {item.score !== undefined && (
                    <span style={{
                      fontSize: '12px', fontWeight: 600,
                      color: item.score >= 75 ? '#22c55e' : item.score >= 50 ? '#f59e0b' : '#ef4444',
                    }}>
                      {item.score}
                    </span>
                  )}
                  <span className={`case-status ${item.status}`}>{item.status}</span>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

