  --color-skip: #94a3b8;
  --radius: 8px;
  --shadow-sm: 0 1px 2px rgba(0,0,0,0.05);
  --shadow-md: 0 4px 6px rgba(0,0,0,0.07);
  --font-sans: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, "Noto Sans SC", sans-serif;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: var(--font-sans);
  background: var(--color-bg);
  color: var(--color-text);
  line-height: 1.6;
}

a {
  color: var(--color-primary);
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

button {
  font-family: inherit;
  cursor: pointer;
}

input, textarea {
  font-family: inherit;
}

:focus-visible {
  outline: 2px solid var(--color-primary);
  outline-offset: 2px;
}

.container {
  max-width: 960px;
  margin: 0 auto;
  padding: 24px 16px;
}

/* Navbar */
.navbar {
  display: flex;
  align-items: center;
  gap: 24px;
  padding: 12px 24px;
  background: var(--color-surface);
  border-bottom: 1px solid var(--color-border);
  box-shadow: var(--shadow-sm);
}

.navbar-brand {
  font-weight: 700;
  font-size: 18px;
  color: var(--color-text);
}

.navbar-links {
  display: flex;
  gap: 16px;
}

.navbar-links a {
  color: var(--color-text-secondary);
  font-size: 14px;
  padding: 6px 12px;
  border-radius: var(--radius);
  transition: all 0.15s;
}

.navbar-links a:hover {
  background: var(--color-bg);
  color: var(--color-text);
}

.navbar-links a.active {
  color: var(--color-primary);
  font-weight: 600;
}

.navbar-links a.disabled {
  color: var(--color-skip);
  cursor: not-allowed;
}

/* Home */
.home-hero {
  text-align: center;
  padding: 48px 0 32px;
}

.home-hero h1 {
  font-size: 32px;
  margin-bottom: 8px;
}

.home-hero .subtitle {
  font-size: 18px;
  color: var(--color-text-secondary);
  margin-bottom: 24px;
}

.home-hero .description {
  font-size: 15px;
  color: var(--color-text-secondary);
  max-width: 600px;
  margin: 0 auto 32px;
}

.home-steps {
  display: flex;
  gap: 16px;
  justify-content: center;
  margin-bottom: 32px;
  flex-wrap: wrap;
}

.home-step {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  padding: 16px 20px;
  width: 200px;
  text-align: center;
  box-shadow: var(--shadow-sm);
}

.home-step .step-number {
  font-size: 24px;
  margin-bottom: 4px;
}

.home-step .step-title {
  font-weight: 600;
  font-size: 15px;
  margin-bottom: 4px;
}

.home-step .step-desc {
  font-size: 13px;
  color: var(--color-text-secondary);
}

.home-input-row {
  display: flex;
  gap: 8px;
  max-width: 600px;
  margin: 0 auto 32px;
}

.home-input-row input {
  flex: 1;
  padding: 12px 16px;
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  font-size: 15px;
}

.home-input-row input:focus {
  border-color: var(--color-primary);
  outline: none;
  box-shadow: 0 0 0 3px rgba(59,130,246,0.15);
}

.btn-primary {
  background: var(--color-primary);
  color: white;
  border: none;
  padding: 12px 24px;
  border-radius: var(--radius);
  font-size: 15px;
  font-weight: 600;
  transition: background 0.15s;
}

.btn-primary:hover {
  background: var(--color-primary-hover);
}

.btn-primary:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.btn-secondary {
  background: var(--color-surface);
  color: var(--color-text);
  border: 1px solid var(--color-border);
  padding: 8px 16px;
  border-radius: var(--radius);
  font-size: 14px;
}

.btn-secondary:hover {
  background: var(--color-bg);
}

.home-demos {
  display: flex;
  gap: 16px;
  justify-content: center;
  margin-bottom: 32px;
  flex-wrap: wrap;
}

.demo-card {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  padding: 16px 20px;
  width: 280px;
  cursor: pointer;
  transition: all 0.15s;
  box-shadow: var(--shadow-sm);
}

.demo-card:hover {
  border-color: var(--color-primary);
  box-shadow: var(--shadow-md);
}

.demo-card .demo-label {
  font-size: 12px;
  color: var(--color-primary);
  font-weight: 600;
  margin-bottom: 4px;
}

.demo-card .demo-title {
  font-size: 15px;
  font-weight: 600;
  margin-bottom: 4px;
}

.demo-card .demo-desc {
  font-size: 13px;
  color: var(--color-text-secondary);
}

.home-history h3 {
  font-size: 16px;
  margin-bottom: 12px;
}

.history-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.history-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 16px;
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  cursor: pointer;
  transition: all 0.15s;
}

.history-item:hover {
  border-color: var(--color-primary);
}

.history-item .case-id {
  font-family: monospace;
  font-size: 13px;
  color: var(--color-text-secondary);
}

.history-item .case-status {
  font-size: 12px;
  padding: 2px 8px;
  border-radius: 4px;
}

.history-item .case-status.done {
  background: rgba(34,197,94,0.1);
  color: var(--color-success);
}

.history-item .case-status.running {
  background: rgba(59,130,246,0.1);
  color: var(--color-primary);
}

.history-item .case-status.error {
  background: rgba(239,68,68,0.1);
  color: var(--color-error);
}

/* Workbench */
.workbench-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 16px;
}

.workbench-topic {
  font-size: 18px;
  font-weight: 600;
}

.workbench-meta {
  display: flex;
  gap: 16px;
  font-size: 13px;
  color: var(--color-text-secondary);
}

.progress-bar-container {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  padding: 16px;
  margin-bottom: 16px;
}

.progress-steps {
  display: flex;
  gap: 4px;
  margin-bottom: 8px;
  flex-wrap: wrap;
}

.progress-step {
  font-size: 12px;
  padding: 2px 8px;
  border-radius: 4px;
  background: var(--color-bg);
  color: var(--color-text-secondary);
}

.progress-step.active {
  background: var(--color-primary);
  color: white;
}

.progress-step.done {
  background: rgba(34,197,94,0.15);
  color: var(--color-success);
}

.progress-track {
  height: 6px;
  background: var(--color-bg);
  border-radius: 3px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  background: var(--color-primary);
  border-radius: 3px;
  transition: width 0.3s;
}

.status-banner {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 16px;
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  margin-bottom: 16px;
}

.status-banner.error {
  border-color: var(--color-error);
  background: rgba(239,68,68,0.05);
}

.status-banner.done {
  border-color: var(--color-success);
  background: rgba(34,197,94,0.05);
}

.status-icon {
  font-size: 20px;
}

.status-text {
  flex: 1;
}

.status-text .status-label {
  font-weight: 600;
  font-size: 15px;
}

.status-text .status-counts {
  font-size: 13px;
  color: var(--color-text-secondary);
}

/* Source Panel */
.source-panel {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  padding: 16px;
  margin-bottom: 16px;
}

.source-panel h3 {
  font-size: 14px;
  margin-bottom: 12px;
}

.source-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: 8px;
}

.source-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  background: var(--color-bg);
  border-radius: 6px;
  font-size: 13px;
}

.source-item .source-name {
  font-weight: 600;
}

.source-item .source-count {
  color: var(--color-text-secondary);
  margin-left: auto;
}

.source-item .source-status-icon {
  font-size: 14px;
}

/* Paper List */
.paper-list {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  padding: 16px;
  margin-bottom: 16px;
}

.paper-list h3 {
  font-size: 14px;
  margin-bottom: 12px;
}

.paper-item {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  padding: 10px 0;
  border-bottom: 1px solid var(--color-border);
  font-size: 14px;
}

.paper-item:last-child {
  border-bottom: none;
}

.paper-item .paper-verdict {
  flex-shrink: 0;
  font-size: 16px;
}

.paper-item .paper-info {
  flex: 1;
}

.paper-item .paper-title {
  font-weight: 500;
  margin-bottom: 2px;
}

.paper-item .paper-meta {
  font-size: 12px;
  color: var(--color-text-secondary);
}

/* Report Sections */
.report-section {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  margin-bottom: 8px;
  overflow: hidden;
}

.report-section summary {
  padding: 12px 16px;
  font-size: 15px;
  font-weight: 600;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 8px;
  user-select: none;
}

.report-section summary:hover {
  background: var(--color-bg);
}

.report-section .report-content {
  padding: 0 16px 16px;
  font-size: 14px;
}

.report-section .report-content pre {
  background: var(--color-bg);
  padding: 12px;
  border-radius: 6px;
  overflow-x: auto;
  font-size: 13px;
  white-space: pre-wrap;
  word-break: break-all;
}

/* Empty/Error/Loading */
.empty-state {
  text-align: center;
  padding: 48px 24px;
}

.empty-state .empty-icon {
  font-size: 48px;
  margin-bottom: 16px;
}

.empty-state .empty-title {
  font-size: 18px;
  font-weight: 600;
  margin-bottom: 8px;
}

.empty-state .empty-desc {
  font-size: 14px;
  color: var(--color-text-secondary);
  margin-bottom: 16px;
}

.error-state {
  text-align: center;
  padding: 48px 24px;
}

.error-state .error-icon {
  font-size: 48px;
  margin-bottom: 16px;
}

.error-state .error-title {
  font-size: 18px;
  font-weight: 600;
  margin-bottom: 8px;
  color: var(--color-error);
}

.error-state .error-message {
  font-size: 14px;
  color: var(--color-text-secondary);
  margin-bottom: 8px;
}

.error-state .error-suggestion {
  font-size: 13px;
  color: var(--color-text);
  background: rgba(59,130,246,0.08);
  padding: 12px 16px;
  border-radius: var(--radius);
  display: inline-block;
  margin-bottom: 16px;
}

.loading-dots {
  display: inline-flex;
  align-items: center;
  gap: 8px;
}

.loading-dots .dots {
  display: inline-flex;
  gap: 4px;
}

.loading-dots .dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--color-primary);
  animation: bounce 1.4s infinite ease-in-out both;
}

.loading-dots .dot:nth-child(1) { animation-delay: -0.32s; }
.loading-dots .dot:nth-child(2) { animation-delay: -0.16s; }

@keyframes bounce {
  0%, 80%, 100% { transform: scale(0); }
  40% { transform: scale(1); }
}

/* Responsive */
@media (max-width: 640px) {
  .home-steps { flex-direction: column; align-items: center; }
  .home-input-row { flex-direction: column; }
  .source-grid { grid-template-columns: 1fr; }
}
